@app.route('/logout', methods=['POST'])
def logout():
    session_id = session.get('session_id')
    
    # Remove from tracking
    if session_id and session_id in mfa_pending_sessions:
        del mfa_pending_sessions[session_id]
    
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username in users_db:
        return jsonify({'error': 'User already exists'}), 400
    
    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    }
    
    return jsonify({
        'message': 'User registered successfully',
        'mfa_secret': users_db[username]['mfa_secret']
    }), 201

# Cleanup old sessions periodically
@app.before_request
def cleanup_sessions():
    current_time = datetime.utcnow()
    expired_sessions = []
    
    for session_id, session_data in mfa_pending_sessions.items():
        if current_time - session_data['created_at'] > timedelta(minutes=30):
            expired_sessions.append(session_id)
    
    for session_id in expired_sessions:
        del mfa_pending_sessions[session_id]

